// // This module implements a 32-register bank with read and write capabilities in a synchronous reset configuration. It allows two registers to be written simultaneously based on the inputs reg_W_addr_A and reg_W_addr_B, returning their values at wdata_A and wdata_B, respectively. A read operation can be performed to a designated register specified by reg_R_addr, using rdata, contingent upon the reg_re (register read enable) signal and with the condition that the register address is not zero. The register set is initialized to zero at startup and reset on the active high reset signal, ensuring all registers start from a known state.
module top_module(
            clk,
			rst,
			reg_R_addr_A, 
			reg_R_addr_B, 
			reg_W_addr, 
			wdata, 
			reg_we, 
			rdata_A, 
			rdata_B
			);input               clk, rst, reg_we;
    input       [ 4: 0] reg_R_addr_A, reg_R_addr_B, reg_W_addr;
    input       [31: 0] wdata;
    output      [31: 0] rdata_A, rdata_B; 

    reg [31:0] register [0:31];
    integer i;

    assign rdata_A = (reg_R_addr_A == 0) ? 0 : register[reg_R_addr_A];
    assign rdata_B = (reg_R_addr_B == 0) ? 0 : register[reg_R_addr_B];

    initial begin
    	for(i = 0; i < 32; i = i + 1)
    		register[i] = 32'h0000_0000 ;
    end

    always @(posedge clk or posedge rst)
    begin
        if (rst == 1) begin
            for(i = 0; i < 32; i = i + 1)
                register[i] <= 0;
        end
        else begin
            if((reg_W_addr != 0) && (reg_we == 1))
                register[reg_W_addr] <= wdata;
        end
    end

endmodule
